INSERT INTO `wp_posts` VALUES (98,1,'2025-04-23 10:00:30','2025-04-23 10:00:30','<!-- wp:heading {\"textAlign\":\"center\",\"level\":1,\"style\":{\"color\":{\"text\":\"#3b8e46\"},\"elements\":{\"link\":{\"color\":{\"text\":\"#3b8e46\"}}}}} -->\n<h1 class=\"wp-block-heading has-text-align-center has-text-color has-link-color\" style=\"color:#3b8e46\">Boisson énergisante 100% naturelle</h1>\n<!-- /wp:heading -->\n\n<!-- wp:group {\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\",\"justifyContent\":\"center\"}} -->\n<div class=\"wp-block-group\"><!-- wp:image {\"id\":89,\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full\"><img src=\"http://planty.local/wp-content/uploads/2025/04/branche-gauche.png\" alt=\"\" class=\"wp-image-89\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:image {\"id\":40,\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full\"><img src=\"http://planty.local/wp-content/uploads/2025/03/Planty6-1.png\" alt=\"\" class=\"wp-image-40\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:image {\"id\":90,\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full\"><img src=\"http://planty.local/wp-content/uploads/2025/04/branche-droite.png\" alt=\"\" class=\"wp-image-90\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:group -->\n\n<!-- wp:heading {\"textAlign\":\"center\"} -->\n<h2 class=\"wp-block-heading has-text-align-center\">L\'énergie des plantes </h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\"} -->\n<p class=\"has-text-align-center\">Planty, c’est la première boisson<br>énergisante composée à 100 % de produits naturels.<br>Avec son goût frais et fruité, retrouvez votre<br>énergie grâce aux plantes riches en vitamine B2,<br>à n’importe quel moment de la journé</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"style\":{\"background\":{\"backgroundImage\":{\"url\":\"http://planty.local/wp-content/uploads/2025/03/jeremy-bezanger-0QgbyZdhX7k-unsplash-1.png\",\"id\":52,\"source\":\"file\",\"title\":\"jeremy-bezanger-0QgbyZdhX7k-unsplash 1\"},\"backgroundSize\":\"cover\"},\"spacing\":{\"padding\":{\"top\":\"var:preset|spacing|80\",\"bottom\":\"var:preset|spacing|80\",\"left\":\"var:preset|spacing|80\",\"right\":\"var:preset|spacing|80\"},\"margin\":{\"top\":\"0\",\"bottom\":\"0\"},\"blockGap\":\"0\"},\"dimensions\":{\"minHeight\":\"400px\"}},\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\"}} -->\n<div class=\"wp-block-group\" style=\"min-height:400px;margin-top:0;margin-bottom:0;padding-top:var(--wp--preset--spacing--80);padding-right:var(--wp--preset--spacing--80);padding-bottom:var(--wp--preset--spacing--80);padding-left:var(--wp--preset--spacing--80)\"><!-- wp:heading {\"textAlign\":\"center\",\"style\":{\"layout\":{\"selfStretch\":\"fill\",\"flexSize\":null},\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-5\"}}},\"typography\":{\"fontSize\":\"100px\"}},\"textColor\":\"ast-global-color-5\"} -->\n<h2 class=\"wp-block-heading has-text-align-center has-ast-global-color-5-color has-text-color has-link-color\" style=\"font-size:100px\">Fraise</h2>\n<!-- /wp:heading --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"fontSize\":\"x-large\"} -->\n<div class=\"wp-block-column has-x-large-font-size\"><!-- wp:group {\"style\":{\"background\":{\"backgroundImage\":{\"url\":\"http://planty.local/wp-content/uploads/2025/03/estudio-bloom-tOitjphtIXU-unsplash-1.png\",\"id\":51,\"source\":\"file\",\"title\":\"estudio-bloom-tOitjphtIXU-unsplash 1\"},\"backgroundSize\":\"cover\",\"backgroundPosition\":\"54% 50%\"},\"spacing\":{\"padding\":{\"top\":\"var:preset|spacing|80\",\"bottom\":\"var:preset|spacing|80\",\"left\":\"var:preset|spacing|80\",\"right\":\"var:preset|spacing|80\"},\"margin\":{\"top\":\"0\",\"bottom\":\"0\"},\"blockGap\":\"0\"},\"dimensions\":{\"minHeight\":\"400px\"}},\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\"}} -->\n<div class=\"wp-block-group\" style=\"min-height:400px;margin-top:0;margin-bottom:0;padding-top:var(--wp--preset--spacing--80);padding-right:var(--wp--preset--spacing--80);padding-bottom:var(--wp--preset--spacing--80);padding-left:var(--wp--preset--spacing--80)\"><!-- wp:heading {\"textAlign\":\"center\",\"style\":{\"layout\":{\"selfStretch\":\"fill\",\"flexSize\":null},\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-5\"}}},\"typography\":{\"fontSize\":\"81px\"}},\"textColor\":\"ast-global-color-5\"} -->\n<h2 class=\"wp-block-heading has-text-align-center has-ast-global-color-5-color has-text-color has-link-color\" style=\"font-size:81px\">Pamplemousse</h2>\n<!-- /wp:heading --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"style\":{\"background\":{\"backgroundImage\":{\"url\":\"http://planty.local/wp-content/uploads/2025/03/rodion-kutsaev-4k8xEFW4_3Q-unsplash-1.png\",\"id\":50,\"source\":\"file\",\"title\":\"rodion-kutsaev-4k8xEFW4_3Q-unsplash 1\"},\"backgroundSize\":\"cover\"},\"spacing\":{\"padding\":{\"top\":\"var:preset|spacing|80\",\"bottom\":\"var:preset|spacing|80\",\"left\":\"var:preset|spacing|80\",\"right\":\"var:preset|spacing|80\"}},\"dimensions\":{\"minHeight\":\"400px\"}},\"fontSize\":\"x-large\",\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\"}} -->\n<div class=\"wp-block-group has-x-large-font-size\" style=\"min-height:400px;padding-top:var(--wp--preset--spacing--80);padding-right:var(--wp--preset--spacing--80);padding-bottom:var(--wp--preset--spacing--80);padding-left:var(--wp--preset--spacing--80)\"><!-- wp:heading {\"textAlign\":\"center\",\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-5\"}}},\"layout\":{\"selfStretch\":\"fill\",\"flexSize\":null},\"typography\":{\"fontSize\":\"81px\"}},\"textColor\":\"ast-global-color-5\"} -->\n<h2 class=\"wp-block-heading has-text-align-center has-ast-global-color-5-color has-text-color has-link-color\" style=\"font-size:81px\">Framboise</h2>\n<!-- /wp:heading --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"style\":{\"background\":{\"backgroundImage\":{\"url\":\"http://planty.local/wp-content/uploads/2025/03/estudio-bloom-ezqnxsqUZ80-unsplash-1.png\",\"id\":49,\"source\":\"file\",\"title\":\"estudio-bloom-ezqnxsqUZ80-unsplash 1\"},\"backgroundSize\":\"cover\"},\"spacing\":{\"padding\":{\"top\":\"var:preset|spacing|80\",\"bottom\":\"var:preset|spacing|80\",\"left\":\"var:preset|spacing|80\",\"right\":\"var:preset|spacing|80\"}},\"dimensions\":{\"minHeight\":\"400px\"}},\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\"}} -->\n<div class=\"wp-block-group\" style=\"min-height:400px;padding-top:var(--wp--preset--spacing--80);padding-right:var(--wp--preset--spacing--80);padding-bottom:var(--wp--preset--spacing--80);padding-left:var(--wp--preset--spacing--80)\"><!-- wp:heading {\"textAlign\":\"center\",\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-5\"}}},\"layout\":{\"selfStretch\":\"fill\",\"flexSize\":null},\"typography\":{\"fontSize\":\"100px\"}},\"textColor\":\"ast-global-color-5\"} -->\n<h2 class=\"wp-block-heading has-text-align-center has-ast-global-color-5-color has-text-color has-link-color\" style=\"font-size:100px\">Citron</h2>\n<!-- /wp:heading --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n<div class=\"wp-block-buttons\"><!-- wp:button -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\">Commander</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons -->','Accueil','','inherit','closed','closed','','7-revision-v1','','','2025-04-23 10:00:30','2025-04-23 10:00:30','',7,'http://planty.local/?p=98',0,'revision','',0);
